#include<bits/stdc++.h>
using namespace std;
int n,m,l[1001],w[1001],dis[1001];
bool vis[1001];
vector<pair<int,int>> mp[1001];
int dijkstra(int x)
{
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,1));
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    dis[1]=0;
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        for(auto i:mp[t])
        {
            int v=i.first,id=i.second;
            int val=w[id];
            if(l[id]>=x&&dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
    return dis[n];
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d%d%d",&u,&v,&w[i],&l[i]);
        mp[u].push_back(make_pair(v,i));
        mp[v].push_back(make_pair(u,i));
    }
    int max1=0;
    for(int i=1;i<=m;i++)
    {
        int c=dijkstra(l[i]),f=l[i];
        max1=max(max1,f*1000000/c);
    }
    printf("%d",max1);
    return 0;
}
